from flask import Flask, session, redirect, url_for, request

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super_gizli_anahtar_buraya_gelmeli' # Üretim ortamında güçlü bir anahtar kullanın

@app.route('/')
def index():
    if 'username' in session:
        return f'Merhaba, {session["username"]}! <a href="/logout">Çıkış Yap</a>'
    return 'Giriş yapmadınız. Lütfen <a href="/login/ornek_kullanici">giriş yapın</a>.'

@app.route('/login/<username>')
def login(username):
    session['username'] = username
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)
